-- ============================================
-- Legislacao full-site: paula-belmonte / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/204377
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = paula-belmonte-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 100 rows Camara legacy existentes, somente 72
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=204377, tipo Deputado(a), ordemAssinatura=1.
-- 28 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'paula-belmonte';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'paula-belmonte: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 100 THEN
    RAISE EXCEPTION 'Pre-condicao paula-belmonte: esperadas 100 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2343123', '2344567', '2343124', '2342905', '2341150', '2345019', '2343128', '2343122', '2342335', '2341983', '2341042', '2340765', '2340573', '2340043', '2339963', '2339956', '2339129', '2336405', '2342307', '2340204', '2339961', '2339888', '2337395', '2336394', '2335204', '2334198', '2332832', '2332321', '2330783', '2327780', '2340985', '2340572', '2337398', '2336401', '2335265', '2334199', '2334192', '2333032', '2332322', '2328331', '2323759', '2339965', '2339150', '2334386', '2334194', '2333871', '2332515', '2331331', '2329009', '2336435', '2336077', '2334195', '2333872', '2332831', '2330764', '2329013', '2334385', '2334193', '2333040', '2331019', '2328332', '2342320', '2339962', '2339955', '2339954', '2339952', '2333873', '2326383', '2334983', '2329410', '2336434', '2336229');
  IF target_present <> 72 THEN
    RAISE EXCEPTION 'Pre-condicao paula-belmonte: esperadas 72 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2343123', '2344567', '2343124', '2342905', '2341150', '2345019', '2343128', '2343122', '2342335', '2341983', '2341042', '2340765', '2340573', '2340043', '2339963', '2339956', '2339129', '2336405', '2342307', '2340204', '2339961', '2339888', '2337395', '2336394', '2335204', '2334198', '2332832', '2332321', '2330783', '2327780', '2340985', '2340572', '2337398', '2336401', '2335265', '2334199', '2334192', '2333032', '2332322', '2328331', '2323759', '2339965', '2339150', '2334386', '2334194', '2333871', '2332515', '2331331', '2329009', '2336435', '2336077', '2334195', '2333872', '2332831', '2330764', '2329013', '2334385', '2334193', '2333040', '2331019', '2328332', '2342320', '2339962', '2339955', '2339954', '2339952', '2333873', '2326383', '2334983', '2329410', '2336434', '2336229')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'paula-belmonte-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao paula-belmonte: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao paula-belmonte: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

